package main

import "fmt"

func main() {
    for i := 1; i <= 5; i++ {
        // The % operator is 'modulo'. 
        // It returns the remainder of division.
        // If a number divided by 2 has a remainder of 1, it's odd.
        if i % 2 != 0 {
            // Skip odd numbers!
            continue
        }

        fmt.Println("Even number:", i)
    }
}
